if(
(NumberofMandatoryDocuments__c == NumberofMandatoryDocumentsUploaded__c || NumberofMandatoryDocuments__c == 0) && (NOT(ISPICKVAL(Final_Risk__c,'')) || ISPICKVAL(KYD_Responsible__c,'RELIANCE')) ,
